export interface GitHubRepo {
  id: number;
  name: string;
  full_name: string;
  description: string | null;
  html_url: string;
  stargazers_count: number;
  forks_count: number;
  language: string | null;
  owner: {
    login: string;
    avatar_url: string;
  };
  updated_at: string;
  topics: string[];
  open_issues_count: number;
}

export interface AIRating {
  score: number;
  reasoning: string;
  pros: string[];
  cons: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface FilterState {
  language: string;
  sort: 'stars' | 'forks' | 'updated';
  minStars: number;
}

import { GitHubRepo, FilterState } from '../types';

const BASE_URL = 'https://api.github.com/search/repositories';

export const searchRepositories = async (
  query: string,
  filters: FilterState
): Promise<GitHubRepo[]> => {
  if (!query.trim()) return [];

  // Construct query string
  let q = query;
  if (filters.language) {
    q += ` language:${filters.language}`;
  }
  if (filters.minStars > 0) {
    q += ` stars:>=${filters.minStars}`;
  }

  const params = new URLSearchParams({
    q,
    sort: filters.sort,
    order: 'desc',
    per_page: '12',
  });

  try {
    const response = await fetch(`${BASE_URL}?${params.toString()}`);
    if (!response.ok) {
      throw new Error(`GitHub API Error: ${response.statusText}`);
    }
    const data = await response.json();
    return data.items || [];
  } catch (error) {
    console.error('Failed to fetch repositories:', error);
    throw error;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { GitHubRepo, AIRating } from '../types';

// Initialize Gemini Client
// CRITICAL: Using process.env.API_KEY as per instructions
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-2.5-flash-latest'; // Fast model for UI interactions

export const getRepoRating = async (repo: GitHubRepo): Promise<AIRating> => {
  if (!apiKey) {
    return {
      score: 0,
      reasoning: "API Key missing. Cannot generate rating.",
      pros: [],
      cons: []
    };
  }

  const prompt = `
    Analyze this GitHub repository based on its metadata:
    Name: ${repo.full_name}
    Description: ${repo.description || 'No description provided'}
    Stars: ${repo.stargazers_count}
    Forks: ${repo.forks_count}
    Open Issues: ${repo.open_issues_count}
    Language: ${repo.language || 'Unknown'}
    Topics: ${repo.topics.join(', ')}
    Last Updated: ${repo.updated_at}

    Rate it out of 10 based on popularity, maintenance (based on update date and issues), and general health. 
    Provide a brief reasoning, 3 pros, and 3 cons.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            reasoning: { type: Type.STRING },
            pros: { type: Type.ARRAY, items: { type: Type.STRING } },
            cons: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["score", "reasoning", "pros", "cons"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIRating;
  } catch (error) {
    console.error("Gemini Rating Error:", error);
    return {
      score: 5,
      reasoning: "AI analysis failed temporarily.",
      pros: ["Available on GitHub"],
      cons: ["Could not analyze further"]
    };
  }
};

export const getChatResponse = async (
  message: string, 
  contextRepo?: GitHubRepo
): Promise<string> => {
  if (!apiKey) return "Please configure your API Key to use the AI helper.";

  let systemInstruction = "You are GitScout, an expert AI software engineer helper. You assist users in finding, understanding, and debugging GitHub repositories.";

  if (contextRepo) {
    systemInstruction += `
      The user is currently looking at the repository: ${contextRepo.full_name}.
      Description: ${contextRepo.description}
      Language: ${contextRepo.language}
      Stats: ${contextRepo.stargazers_count} stars.
      Use this context to answer questions if relevant.
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: message,
      config: {
        systemInstruction: systemInstruction,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I'm having trouble connecting to the AI brain right now.";
  }
};

import React, { useState } from 'react';
import { Star, GitFork, AlertCircle, ExternalLink, Bot, MessageSquare } from 'lucide-react';
import { GitHubRepo, AIRating } from '../types';
import { getRepoRating } from '../services/geminiService';

interface RepoCardProps {
  repo: GitHubRepo;
  onSelectForChat: (repo: GitHubRepo) => void;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, onSelectForChat }) => {
  const [rating, setRating] = useState<AIRating | null>(null);
  const [loadingRating, setLoadingRating] = useState(false);

  const handleAnalyze = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (rating) return;

    setLoadingRating(true);
    try {
      const data = await getRepoRating(repo);
      setRating(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingRating(false);
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 8) return 'text-green-400';
    if (score >= 5) return 'text-yellow-400';
    return 'text-red-400';
  };

  return (
    <div className="bg-surface border border-slate-700 rounded-xl p-5 hover:border-primary/50 transition-all duration-300 flex flex-col h-full shadow-lg relative overflow-hidden group">

      {/* Top Header */}
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center gap-3">
          <img 
            src={repo.owner.avatar_url} 
            alt={repo.owner.login} 
            className="w-10 h-10 rounded-full border border-slate-600"
          />
          <div>
            <h3 className="font-bold text-lg text-blue-400 truncate max-w-[200px] hover:underline">
              <a href={repo.html_url} target="_blank" rel="noopener noreferrer">{repo.name}</a>
            </h3>
            <p className="text-xs text-slate-400">by {repo.owner.login}</p>
          </div>
        </div>
        <div className="flex items-center gap-1 bg-slate-800 px-2 py-1 rounded text-xs text-slate-300">
           <span className="w-2 h-2 rounded-full bg-blue-500 block"></span>
           {repo.language || 'N/A'}
        </div>
      </div>

      {/* Description */}
      <p className="text-sm text-slate-300 mb-4 line-clamp-3 flex-grow">
        {repo.description || 'No description provided.'}
      </p>

      {/* Topics */}
      <div className="flex flex-wrap gap-2 mb-4">
        {repo.topics.slice(0, 3).map(topic => (
          <span key={topic} className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full border border-slate-700">
            {topic}
          </span>
        ))}
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-3 gap-2 mb-4 text-xs text-slate-400 border-t border-slate-700 pt-3">
        <div className="flex items-center gap-1">
          <Star size={14} className="text-yellow-500" />
          <span>{repo.stargazers_count.toLocaleString()}</span>
        </div>
        <div className="flex items-center gap-1">
          <GitFork size={14} className="text-slate-500" />
          <span>{repo.forks_count.toLocaleString()}</span>
        </div>
        <div className="flex items-center gap-1">
          <AlertCircle size={14} className="text-red-400" />
          <span>{repo.open_issues_count.toLocaleString()}</span>
        </div>
      </div>

      {/* AI Section */}
      <div className="mt-auto">
        {!rating ? (
           <button 
             onClick={handleAnalyze}
             disabled={loadingRating}
             className="w-full py-2 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white text-xs font-semibold rounded-lg flex items-center justify-center gap-2 transition-all"
           >
             {loadingRating ? (
               <span className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></span>
             ) : (
               <>
                 <Bot size={16} /> Analyze & Rate
               </>
             )}
           </button>
        ) : (
          <div className="bg-slate-800/50 rounded-lg p-3 text-xs animate-in fade-in slide-in-from-bottom-2 duration-300">
            <div className="flex justify-between items-center mb-2">
              <span className="font-bold text-slate-200">AI Score</span>
              <span className={`font-black text-lg ${getScoreColor(rating.score)}`}>{rating.score}/10</span>
            </div>
            <p className="text-slate-400 mb-2 italic">"{rating.reasoning}"</p>
            <div className="space-y-1">
              {rating.pros.slice(0, 1).map((pro, i) => (
                <div key={i} className="flex items-start gap-1 text-green-400/80">
                   <span>+</span> {pro}
                </div>
              ))}
               {rating.cons.slice(0, 1).map((con, i) => (
                <div key={i} className="flex items-start gap-1 text-red-400/80">
                   <span>-</span> {con}
                </div>
              ))}
            </div>
          </div>
        )}

        <button
          onClick={() => onSelectForChat(repo)}
          className="w-full mt-2 py-1.5 border border-slate-600 hover:bg-slate-700 text-slate-300 text-xs font-medium rounded-lg flex items-center justify-center gap-2 transition-colors"
        >
          <MessageSquare size={14} />
          Ask Assistant
        </button>
      </div>
    </div>
  );
};

export default RepoCard;

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, Minimize2, Maximize2, Sparkles, Code2 } from 'lucide-react';
import { ChatMessage, GitHubRepo } from '../types';
import { getChatResponse } from '../services/geminiService';

interface AIChatProps {
  isOpen: boolean;
  onClose: () => void;
  contextRepo?: GitHubRepo | null;
}

const AIChat: React.FC<AIChatProps> = ({ isOpen, onClose, contextRepo }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hi! I can help you understand repos, debug issues, or explain code. Select a repository to get specific help!', timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen, isMinimized]);

  useEffect(() => {
    if (contextRepo) {
      setMessages(prev => [
        ...prev, 
        { role: 'model', text: `I see you're looking at **${contextRepo.name}**. How can I help you with this repository?`, timestamp: Date.now() }
      ]);
      if (isMinimized) setIsMinimized(false);
    }
  }, [contextRepo]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const response = await getChatResponse(userMsg.text, contextRepo || undefined);
      setMessages(prev => [...prev, { role: 'model', text: response, timestamp: Date.now() }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Sorry, I encountered an error.", timestamp: Date.now() }]);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  if (isMinimized) {
    return (
      <button
        onClick={() => setIsMinimized(false)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full shadow-xl flex items-center justify-center text-white z-50 transition-all hover:scale-110"
      >
        <Bot size={28} />
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-[90vw] md:w-[400px] h-[600px] max-h-[80vh] bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl flex flex-col overflow-hidden z-50 animate-in slide-in-from-bottom-10 fade-in duration-300">
      {/* Header */}
      <div className="bg-slate-800 p-4 flex justify-between items-center border-b border-slate-700">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
            <Bot size={18} className="text-white" />
          </div>
          <div>
            <h3 className="font-bold text-slate-100">GitScout AI</h3>
            <p className="text-[10px] text-slate-400 flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
              Online
            </p>
          </div>
        </div>
        <div className="flex items-center gap-1 text-slate-400">
          <button onClick={() => setIsMinimized(true)} className="p-1.5 hover:bg-slate-700 rounded transition-colors">
            <Minimize2 size={16} />
          </button>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-700 rounded transition-colors hover:text-red-400">
            <X size={16} />
          </button>
        </div>
      </div>

      {/* Context Banner */}
      {contextRepo && (
        <div className="bg-blue-900/20 px-4 py-2 text-xs text-blue-300 border-b border-blue-900/30 flex items-center gap-2">
           <Code2 size={12} />
           Context: <span className="font-semibold">{contextRepo.full_name}</span>
        </div>
      )}

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/95">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : 'bg-slate-800 text-slate-200 rounded-bl-none border border-slate-700'
              }`}
            >
              <div className="whitespace-pre-wrap">{msg.text}</div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-slate-800 rounded-2xl rounded-bl-none px-4 py-3 border border-slate-700 flex items-center gap-2">
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-slate-800 border-t border-slate-700">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={contextRepo ? "Ask about this repo..." : "Ask for debugging help..."}
            className="flex-1 bg-slate-900 border border-slate-600 text-slate-200 text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-blue-500 transition-colors"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || loading}
            className="bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-xl disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import React from 'react';
import { FilterState } from '../types';
import { Filter } from 'lucide-react';

interface FilterBarProps {
  filters: FilterState;
  onChange: (filters: FilterState) => void;
}

const FilterBar: React.FC<FilterBarProps> = ({ filters, onChange }) => {
  const handleChange = (key: keyof FilterState, value: any) => {
    onChange({ ...filters, [key]: value });
  };

  return (
    <div className="flex flex-wrap gap-4 items-center bg-surface p-4 rounded-xl border border-slate-700 mb-6">
      <div className="flex items-center gap-2 text-slate-400 mr-2">
        <Filter size={18} />
        <span className="text-sm font-medium">Filters</span>
      </div>

      <select
        value={filters.language}
        onChange={(e) => handleChange('language', e.target.value)}
        className="bg-slate-800 text-slate-200 text-sm border border-slate-600 rounded-lg px-3 py-2 focus:outline-none focus:border-blue-500"
      >
        <option value="">All Languages</option>
        <option value="javascript">JavaScript</option>
        <option value="typescript">TypeScript</option>
        <option value="python">Python</option>
        <option value="java">Java</option>
        <option value="go">Go</option>
        <option value="rust">Rust</option>
        <option value="html">HTML/CSS</option>
      </select>

      <select
        value={filters.sort}
        onChange={(e) => handleChange('sort', e.target.value)}
        className="bg-slate-800 text-slate-200 text-sm border border-slate-600 rounded-lg px-3 py-2 focus:outline-none focus:border-blue-500"
      >
        <option value="stars">Most Stars</option>
        <option value="forks">Most Forks</option>
        <option value="updated">Recently Updated</option>
      </select>

      <div className="flex items-center gap-2 bg-slate-800 border border-slate-600 rounded-lg px-3 py-2">
        <span className="text-xs text-slate-400">Min Stars:</span>
        <input
          type="number"
          min="0"
          value={filters.minStars}
          onChange={(e) => handleChange('minStars', Number(e.target.value))}
          className="bg-transparent text-slate-200 text-sm w-20 focus:outline-none"
        />
      </div>
    </div>
  );
};

export default FilterBar;

import React, { useState, useEffect } from 'react';
import { Search, Github, Loader2 } from 'lucide-react';
import { GitHubRepo, FilterState } from './types';
import { searchRepositories } from './services/githubService';
import RepoCard from './components/RepoCard';
import FilterBar from './components/FilterBar';
import AIChat from './components/AIChat';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [filters, setFilters] = useState<FilterState>({
    language: '',
    sort: 'stars',
    minStars: 0,
  });

  // Chat state
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatContext, setChatContext] = useState<GitHubRepo | null>(null);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setError('');

    try {
      const data = await searchRepositories(query, filters);
      setRepos(data);
      if (data.length === 0) setError('No repositories found matching your criteria.');
    } catch (err) {
      setError('Failed to fetch repositories. Please try again later.');
    } finally {
      setLoading(false);
    }
  };

  const openChatWithContext = (repo: GitHubRepo) => {
    setChatContext(repo);
    setIsChatOpen(true);
  };

  return (
    <div className="min-h-screen bg-background text-slate-200 pb-20 relative">
      {/* Navbar */}
      <nav className="border-b border-slate-800 bg-surface/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Github className="text-white" size={28} />
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-500 text-transparent bg-clip-text">
              GitScout AI
            </h1>
          </div>
          <button 
            onClick={() => { setChatContext(null); setIsChatOpen(true); }}
            className="text-sm font-medium text-slate-300 hover:text-white transition-colors flex items-center gap-2"
          >
             Open AI Helper
          </button>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Hero / Search Section */}
        <div className="text-center mb-10 space-y-4">
          <h2 className="text-4xl font-black text-white tracking-tight sm:text-5xl">
            Find & Analyze <br />
            <span className="text-blue-500">GitHub Repositories</span>
          </h2>
          <p className="text-slate-400 max-w-2xl mx-auto text-lg">
            Search for any library, framework, or tool. Our AI rates them for you and helps you debug.
          </p>

          <form onSubmit={handleSearch} className="max-w-2xl mx-auto relative mt-8">
            <input 
              type="text" 
              placeholder="Search for 'react state management', 'machine learning', etc..." 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              className="w-full bg-surface border border-slate-700 text-white rounded-2xl py-4 pl-12 pr-4 shadow-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-lg placeholder:text-slate-500"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={24} />
            <button 
              type="submit"
              className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 text-white px-6 rounded-xl font-medium transition-colors"
            >
              Search
            </button>
          </form>
        </div>

        {/* Filters */}
        <div className="max-w-7xl mx-auto">
          <FilterBar filters={filters} onChange={setFilters} />
        </div>

        {/* Content Area */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Loader2 size={48} className="animate-spin mb-4 text-blue-500" />
            <p>Scouting repositories...</p>
          </div>
        ) : error ? (
          <div className="text-center py-20 text-red-400 bg-red-900/10 rounded-xl border border-red-900/50">
            <p>{error}</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {repos.map((repo) => (
              <RepoCard 
                key={repo.id} 
                repo={repo} 
                onSelectForChat={openChatWithContext}
              />
            ))}
          </div>
        )}

        {!loading && repos.length === 0 && !error && (
          <div className="text-center py-20 text-slate-500">
            <p>Enter a keyword above to start scouting.</p>
          </div>
        )}
      </main>

      {/* AI Chat Widget */}
      <AIChat 
        isOpen={isChatOpen} 
        onClose={() => setIsChatOpen(false)} 
        contextRepo={chatContext}
      />
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { GitHubRepo, AIRating } from '../types';

// Initialize Gemini Client
// CRITICAL: Using process.env.API_KEY as per instructions
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-2.5-flash-latest'; // Fast model for UI interactions

export const enhanceSearchQuery = async (query: string): Promise<string> => {
  if (!apiKey) return query;

  const prompt = `
    You are a search query optimizer for GitHub.
    Convert the following natural language user input into a set of 2-5 distinct, highly relevant keywords for a GitHub repository search.

    Rules:
    1. Remove filler words (a, the, in, for, I want to find, show me).
    2. Identify the core technology (e.g., "react", "python") and the specific problem/domain (e.g., "charts", "auth").
    3. If the user asks a question, extract the topic (e.g., "how to build a bot" -> "discord bot framework").
    4. Do not include qualifiers like "language:javascript" or "stars:>100" unless explicitly asked for, focus on content keywords.
    5. Return ONLY the space-separated keywords string. No quotes, no explanations.

    Input: "${query}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
    });
    const text = response.text?.trim();
    // Fallback if AI returns something weird or empty
    return text || query;
  } catch (error) {
    console.error("Query enhancement failed", error);
    return query;
  }
};

export const getRepoRating = async (repo: GitHubRepo): Promise<AIRating> => {
  if (!apiKey) {
    return {
      score: 0,
      reasoning: "API Key missing. Cannot generate rating.",
      pros: [],
      cons: []
    };
  }

  const prompt = `
    Analyze this GitHub repository based on its metadata:
    Name: ${repo.full_name}
    Description: ${repo.description || 'No description provided'}
    Stars: ${repo.stargazers_count}
    Forks: ${repo.forks_count}
    Open Issues: ${repo.open_issues_count}
    Language: ${repo.language || 'Unknown'}
    Topics: ${repo.topics.join(', ')}
    Last Updated: ${repo.updated_at}

    Rate it out of 10 based on popularity, maintenance (based on update date and issues), and general health. 
    Provide a brief reasoning, 3 pros, and 3 cons.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            reasoning: { type: Type.STRING },
            pros: { type: Type.ARRAY, items: { type: Type.STRING } },
            cons: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["score", "reasoning", "pros", "cons"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIRating;
  } catch (error) {
    console.error("Gemini Rating Error:", error);
    return {
      score: 5,
      reasoning: "AI analysis failed temporarily.",
      pros: ["Available on GitHub"],
      cons: ["Could not analyze further"]
    };
  }
};

export const getChatResponse = async (
  message: string, 
  contextRepo?: GitHubRepo
): Promise<string> => {
  if (!apiKey) return "Please configure your API Key to use the AI helper.";

  let systemInstruction = "You are GitScout, an expert AI software engineer helper. You assist users in finding, understanding, and debugging GitHub repositories.";

  if (contextRepo) {
    systemInstruction += `
      The user is currently looking at the repository: ${contextRepo.full_name}.
      Description: ${contextRepo.description}
      Language: ${contextRepo.language}
      Stats: ${contextRepo.stargazers_count} stars.
      Use this context to answer questions if relevant.
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: message,
      config: {
        systemInstruction: systemInstruction,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I'm having trouble connecting to the AI brain right now.";
  }
};

import React, { useState, useEffect } from 'react';
import { Search, Github, Loader2, Sparkles, ToggleLeft, ToggleRight } from 'lucide-react';
import { GitHubRepo, FilterState } from './types';
import { searchRepositories } from './services/githubService';
import { enhanceSearchQuery } from './services/geminiService';
import RepoCard from './components/RepoCard';
import FilterBar from './components/FilterBar';
import AIChat from './components/AIChat';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [error, setError] = useState('');
  const [smartSearch, setSmartSearch] = useState(true);
  const [filters, setFilters] = useState<FilterState>({
    language: '',
    sort: 'stars',
    minStars: 0,
  });

  // Chat state
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatContext, setChatContext] = useState<GitHubRepo | null>(null);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setError('');

    try {
      let finalQuery = query;

      // Smart Search Step
      if (smartSearch) {
        setEnhancing(true);
        try {
          finalQuery = await enhanceSearchQuery(query);
          console.log(`Smart Search: "${query}" -> "${finalQuery}"`);
        } catch (err) {
          console.error("Enhancement failed, using original query");
        } finally {
          setEnhancing(false);
        }
      }

      const data = await searchRepositories(finalQuery, filters);
      setRepos(data);
      if (data.length === 0) setError(`No repositories found matching "${finalQuery}".`);
    } catch (err) {
      setError('Failed to fetch repositories. Please try again later.');
    } finally {
      setLoading(false);
      setEnhancing(false);
    }
  };

  const openChatWithContext = (repo: GitHubRepo) => {
    setChatContext(repo);
    setIsChatOpen(true);
  };

  return (
    <div className="min-h-screen bg-background text-slate-200 pb-20 relative">
      {/* Navbar */}
      <nav className="border-b border-slate-800 bg-surface/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Github className="text-white" size={28} />
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-500 text-transparent bg-clip-text">
              GitScout AI
            </h1>
          </div>
          <button 
            onClick={() => { setChatContext(null); setIsChatOpen(true); }}
            className="text-sm font-medium text-slate-300 hover:text-white transition-colors flex items-center gap-2"
          >
             Open AI Helper
          </button>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Hero / Search Section */}
        <div className="text-center mb-10 space-y-4">
          <h2 className="text-4xl font-black text-white tracking-tight sm:text-5xl">
            Find & Analyze <br />
            <span className="text-blue-500">GitHub Repositories</span>
          </h2>
          <p className="text-slate-400 max-w-2xl mx-auto text-lg">
            Search for any library, framework, or tool. Our AI rates them for you and helps you debug.
          </p>

          <form onSubmit={handleSearch} className="max-w-2xl mx-auto mt-8 relative group">
            <div className="relative">
              <input 
                type="text" 
                placeholder={smartSearch ? "Describe what you need (e.g., 'charts for react')" : "Search exactly (e.g., 'recharts')"}
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-surface border border-slate-700 text-white rounded-2xl py-4 pl-12 pr-4 shadow-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-lg placeholder:text-slate-500"
              />
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={24} />
              <button 
                type="submit"
                disabled={loading || enhancing}
                className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 disabled:bg-blue-600/50 text-white px-6 rounded-xl font-medium transition-colors flex items-center gap-2"
              >
                {(loading || enhancing) ? (
                  <Loader2 className="animate-spin" size={20} />
                ) : (
                  "Search"
                )}
              </button>
            </div>

            {/* Smart Search Toggle */}
            <div className="absolute -bottom-8 right-2 flex items-center gap-2 cursor-pointer" onClick={() => setSmartSearch(!smartSearch)}>
               <span className={`text-xs font-medium ${smartSearch ? 'text-blue-400' : 'text-slate-500'}`}>
                 AI Smart Search
               </span>
               <div className={`transition-colors duration-200 ${smartSearch ? 'text-blue-500' : 'text-slate-600'}`}>
                 {smartSearch ? <ToggleRight size={24} /> : <ToggleLeft size={24} />}
               </div>
            </div>
            {smartSearch && (
              <div className="absolute -bottom-8 left-4 text-xs text-blue-400/70 flex items-center gap-1">
                 <Sparkles size={12} />
                 <span>Enhancing queries enabled</span>
              </div>
            )}
          </form>
        </div>

        {/* Filters */}
        <div className="max-w-7xl mx-auto mt-12">
          <FilterBar filters={filters} onChange={setFilters} />
        </div>

        {/* Content Area */}
        {enhancing ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Sparkles size={48} className="animate-pulse mb-4 text-purple-500" />
            <p className="text-purple-300">AI is optimizing your search...</p>
          </div>
        ) : loading ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Loader2 size={48} className="animate-spin mb-4 text-blue-500" />
            <p>Scouting repositories...</p>
          </div>
        ) : error ? (
          <div className="text-center py-20 text-red-400 bg-red-900/10 rounded-xl border border-red-900/50">
            <p>{error}</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {repos.map((repo) => (
              <RepoCard 
                key={repo.id} 
                repo={repo} 
                onSelectForChat={openChatWithContext}
              />
            ))}
          </div>
        )}

        {!loading && !enhancing && repos.length === 0 && !error && (
          <div className="text-center py-20 text-slate-500">
            <p>Enter a keyword above to start scouting.</p>
          </div>
        )}
      </main>

      {/* AI Chat Widget */}
      <AIChat 
        isOpen={isChatOpen} 
        onClose={() => setIsChatOpen(false)} 
        contextRepo={chatContext}
      />
    </div>
  );
};

export default App;

