import { GitHubRepo, AIRating } from '../types';
import { getRepoRating } from '../services/geminiService';

interface RepoCardProps {
  repo: GitHubRepo;
  onSelectForChat: (repo: GitHubRepo) => void;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, onSelectForChat }) => {
  const [rating, setRating] = useState<AIRating | null>(null);
  const [loadingRating, setLoadingRating] = useState(false);

  const handleAnalyze = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (rating) return;

    setLoadingRating(true);
    try {
      const data = await getRepoRating(repo);
      setRating(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingRating(false);
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 8) return 'text-green-400';
    if (score >= 5) return 'text-yellow-400';
    return 'text-red-400';
  };

  return (
    <div className="bg-surface border border-slate-700 rounded-xl p-5 hover:border-primary/50 transition-all duration-300 flex flex-col h-full shadow-lg relative overflow-hidden group">

      {/* Top Header */}
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center gap-3">
          <img 
            src={repo.owner.avatar_url} 
            alt={repo.owner.login} 
            className="w-10 h-10 rounded-full border border-slate-600"
          />
          <div>
            <h3 className="font-bold text-lg text-blue-400 truncate max-w-[200px] hover:underline">
              <a href={repo.html_url} target="_blank" rel="noopener noreferrer">{repo.name}</a>
            </h3>
            <p className="text-xs text-slate-400">by {repo.owner.login}</p>
          </div>
        </div>
        <div className="flex items-center gap-1 bg-slate-800 px-2 py-1 rounded text-xs text-slate-300">
           <span className="w-2 h-2 rounded-full bg-blue-500 block"></span>
           {repo.language || 'N/A'}
        </div>
      </div>

      {/* Description */}
      <p className="text-sm text-slate-300 mb-4 line-clamp-3 flex-grow">
        {repo.description || 'No description provided.'}
      </p>

      {/* Topics */}
      <div className="flex flex-wrap gap-2 mb-4">
        {repo.topics.slice(0, 3).map(topic => (
          <span key={topic} className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full border border-slate-700">
