        <div className="flex items-center gap-1">
          <GitFork size={14} className="text-slate-500" />
          <span>{repo.forks_count.toLocaleString()}</span>
        </div>
        <div className="flex items-center gap-1">
          <AlertCircle size={14} className="text-red-400" />
          <span>{repo.open_issues_count.toLocaleString()}</span>
        </div>
      </div>

      {/* AI Section */}
      <div className="mt-auto">
        {!rating ? (
           <button 
             onClick={handleAnalyze}
             disabled={loadingRating}
             className="w-full py-2 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white text-xs font-semibold rounded-lg flex items-center justify-center gap-2 transition-all"
           >
             {loadingRating ? (
               <span className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></span>
             ) : (
               <>
                 <Bot size={16} /> Analyze & Rate
               </>
             )}
           </button>
        ) : (
          <div className="bg-slate-800/50 rounded-lg p-3 text-xs animate-in fade-in slide-in-from-bottom-2 duration-300 border border-slate-700/50">
            <div className="flex justify-between items-center mb-2">
              <span className="font-bold text-slate-200">AI Score</span>
              <span className={`font-black text-lg ${getScoreColor(rating.score)}`}>{rating.score}/10</span>
            </div>
            <p className="text-slate-400 mb-3 italic border-b border-slate-700/50 pb-2">"{rating.reasoning}"</p>

            {/* Pros & Cons */}
            <div className="grid grid-cols-2 gap-2 mb-3">
               <div>
                  <p className="text-[10px] font-semibold text-green-400 mb-1">Pros</p>
                  {rating.pros.slice(0, 2).map((pro, i) => (
                    <div key={i} className="text-[10px] text-slate-400 truncate flex items-center gap-1">
                       <span className="text-green-500">+</span> {pro}
                    </div>
                  ))}
               </div>
               <div>
                  <p className="text-[10px] font-semibold text-red-400 mb-1">Cons</p>
                  {rating.cons.slice(0, 2).map((con, i) => (
                    <div key={i} className="text-[10px] text-slate-400 truncate flex items-center gap-1">
                       <span className="text-red-500">-</span> {con}
                    </div>
                  ))}
               </div>
            </div>

            {/* New Insights Section */}
            <div className="space-y-2 pt-2 border-t border-slate-700/50">
                <div>
                   <div className="flex items-center gap-1.5 mb-1.5">
                      <Lightbulb size={12} className="text-amber-400" />
                      <p className="text-[10px] font-bold text-amber-100">Best Use Cases</p>
                   </div>
                   <div className="flex flex-wrap gap-1.5">
                      {rating.useCases.slice(0, 3).map((u, i) => (
                         <span key={i} className="px-1.5 py-0.5 bg-amber-900/20 text-amber-200/80 rounded border border-amber-900/30 text-[10px] whitespace-nowrap">
                            {u}
                         </span>
                      ))}
                   </div>
                </div>

                <div>
                   <div className="flex items-center gap-1.5 mb-1.5">
                      <Layers size={12} className="text-indigo-400" />
                      <p className="text-[10px] font-bold text-indigo-100">Related Tech</p>
                   </div>
                   <div className="flex flex-wrap gap-1.5">
                      {rating.relatedTech.slice(0, 3).map((t, i) => (
                         <span key={i} className="px-1.5 py-0.5 bg-indigo-900/20 text-indigo-200/80 rounded border border-indigo-900/30 text-[10px] whitespace-nowrap">
                            {t}
                         </span>
                      ))}
