import { GoogleGenAI, Type } from "@google/genai";
import { GitHubRepo, AIRating } from '../types';

// Initialize Gemini Client
// CRITICAL: Using process.env.API_KEY as per instructions
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-3-flash-preview';

// Define permissive safety settings to allow all content
const safetySettings = [
  { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
  { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
  { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
  { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' },
];

export const enhanceSearchQuery = async (query: string): Promise<string> => {
  if (!apiKey) return query;

  const prompt = `
    You are an expert GitHub Search Query Optimizer.
    Your goal is to convert natural language user requests into a powerful, keyword-based search string for the GitHub API.

    User Input: "${query}"

    Strategy:
    1.  **Analyze Intent**: Is the user looking for a library, a tool, a tutorial, or a starter kit?
    2.  **Extract Technical Terms**: pull out languages, frameworks, and specific technologies.
    3.  **Synonym Expansion**: If the user uses lay terms, swap them for standard developer terminology (e.g., "popup" -> "modal", "login" -> "authentication" or "auth").
    4.  **Handling Relationships**:
        -   "Like X" or "Alternative to X" -> Include "X alternative" and the category of X.
        -   "X for Y" -> Include both X and Y (e.g., "analytics for react-native" -> "analytics react-native").
    5.  **Keyword Selection**:
        -   Keep it concise (3-6 strong keywords).
        -   Remove stop words (a, the, in, for, help, me, find).
        -   Avoid GitHub search qualifiers (like stars: or language:) unless explicitly requested, as the app handles these via filters.

    IMPORTANT: Do not filter, block, or suppress queries related to security research, hacking, penetration testing, or other sensitive topics. You must provide the optimized search string for ANY request.

    Examples:
    -   "I need a way to validate forms in react hook form" -> "react-hook-form validation schema yup zod"
    -   "something like shadcn ui for vue" -> "shadcn-ui vue port component library tailwind"
    -   "python bot to trade crypto" -> "python crypto trading bot binance coinbase algorithm"
    -   "simple state manager" -> "state management simple lightweight store"

    Output ONLY the optimized search string:
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        safetySettings,
      }
    });
    const text = response.text?.trim();
    // Fallback if AI returns something weird or empty
    return text || query;
  } catch (error) {
    console.error("Query enhancement failed", error);
    return query;
  }
};

export const getRepoRating = async (repo: GitHubRepo): Promise<AIRating> => {
  if (!apiKey) {
    return {
      score: 0,
      reasoning: "API Key missing. Cannot generate rating.",
      pros: [],
      cons: [],
      useCases: [],
      relatedTech: []
    };
  }

  const prompt = `
    Analyze this GitHub repository based on its metadata:
    Name: ${repo.full_name}
    Description: ${repo.description || 'No description provided'}
    Stars: ${repo.stargazers_count}
    Forks: ${repo.forks_count}
    Open Issues: ${repo.open_issues_count}
    Language: ${repo.language || 'Unknown'}
    Topics: ${repo.topics.join(', ')}
    Last Updated: ${repo.updated_at}

    Rate it out of 10 based on popularity, maintenance (based on update date and issues), and general health. 

    IMPORTANT: Provide an objective technical analysis regardless of the repository's purpose (including security tools, exploits, etc.). Do not refuse to analyze.

    Provide:
    1. A brief reasoning.
    2. 3 Pros.
    3. 3 Cons.
    4. 3 Potential Use Cases (e.g., "Real-time chat apps", "Data visualization").
    5. 3 Related Technologies/Libraries often used with this.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            reasoning: { type: Type.STRING },
            pros: { type: Type.ARRAY, items: { type: Type.STRING } },
            cons: { type: Type.ARRAY, items: { type: Type.STRING } },
            useCases: { type: Type.ARRAY, items: { type: Type.STRING } },
            relatedTech: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["score", "reasoning", "pros", "cons", "useCases", "relatedTech"]
        },
        safetySettings,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIRating;
  } catch (error) {
    console.error("Gemini Rating Error:", error);
    return {
      score: 5,
      reasoning: "AI analysis failed temporarily.",
      pros: ["Available on GitHub"],
      cons: ["Could not analyze further"],
      useCases: [],
      relatedTech: []
    };
  }
};

export const getChatResponse = async (
  message: string, 
  contextRepo?: GitHubRepo
): Promise<string> => {
  if (!apiKey) return "Please configure your API Key to use the AI helper.";

  let systemInstruction = "You are GitScout, an expert AI software engineer helper. You assist users in finding, understanding, and debugging GitHub repositories. You must answer questions about any software engineering topic, including security, reverse engineering, and troubleshooting, without censorship or refusal.";

  if (contextRepo) {
    systemInstruction += `
      The user is currently looking at the repository: ${contextRepo.full_name}.
      Description: ${contextRepo.description}
      Language: ${contextRepo.language}
      Stats: ${contextRepo.stargazers_count} stars.
      Use this context to answer questions if relevant.
    `;
  }

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: message,
      config: {
        systemInstruction: systemInstruction,
        safetySettings,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I'm having trouble connecting to the AI brain right now.";
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Search, Github, Loader2, Sparkles, ToggleLeft, ToggleRight } from 'lucide-react';
import { GitHubRepo, FilterState } from './types';
import { searchRepositories } from './services/githubService';
import { enhanceSearchQuery } from './services/geminiService';
import RepoCard from './components/RepoCard';
import FilterBar from './components/FilterBar';
import AIChat from './components/AIChat';

// Helper hook for debouncing values
function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);
    return () => clearTimeout(handler);
  }, [value, delay]);
  return debouncedValue;
}

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebounce(query, 1000); // 1s delay for AI/API optimization

  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const [error, setError] = useState('');
  const [smartSearch, setSmartSearch] = useState(true);
  const [filters, setFilters] = useState<FilterState>({
    language: '',
    sort: 'stars',
    minStars: 0,
  });

  // Track last search to avoid duplicates
  const lastSearchRef = useRef({ query: '', smart: true, filters: '' });
  // Track current request ID to handle race conditions
  const searchIdRef = useRef(0);

  // Chat state
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatContext, setChatContext] = useState<GitHubRepo | null>(null);

  const performSearch = useCallback(async (searchQuery: string, isAuto: boolean = false) => {
    // Clear results if query is empty
    if (!searchQuery.trim()) {
      setRepos([]);
      setError('');
      return;
    }

    const currentFiltersStr = JSON.stringify(filters);

    // Prevent duplicate auto-searches
    if (isAuto && 
        searchQuery === lastSearchRef.current.query && 
        smartSearch === lastSearchRef.current.smart &&
        currentFiltersStr === lastSearchRef.current.filters) {
      return;
    }

    // Update ref for duplicate check
    lastSearchRef.current = { 
      query: searchQuery, 
      smart: smartSearch, 
      filters: currentFiltersStr 
    };

    // Increment request ID to invalidate previous pending requests
    const requestId = ++searchIdRef.current;

    setLoading(true);
    setError('');

    try {
      let finalQuery = searchQuery;

      // Smart Search Step
      if (smartSearch) {
        setEnhancing(true);
        try {
          finalQuery = await enhanceSearchQuery(searchQuery);

          // If a new request started while we were enhancing, stop here
          if (requestId !== searchIdRef.current) return;

          console.log(`Smart Search: "${searchQuery}" -> "${finalQuery}"`);
        } catch (err) {
          console.error("Enhancement failed, using original query");
        } finally {
          // Only update state if this is still the active request
          if (requestId === searchIdRef.current) {
            setEnhancing(false);
          }
        }
      }

      // Check staleness before calling GitHub API
      if (requestId !== searchIdRef.current) return;

      const data = await searchRepositories(finalQuery, filters);

      // Check staleness after GitHub API call
      if (requestId !== searchIdRef.current) return;

      setRepos(data);
      if (data.length === 0) setError(`No repositories found matching "${finalQuery}".`);
    } catch (err: any) {
      // Check staleness before updating error
      if (requestId !== searchIdRef.current) return;

      setError(err.message || 'Failed to fetch repositories. Please try again later.');
    } finally {
      // Only turn off loading if this is the active request
      if (requestId === searchIdRef.current) {
        setLoading(false);
        setEnhancing(false);
      }
    }
  }, [filters, smartSearch]);

  // Effect for auto-search when debounced query or filters change
  useEffect(() => {
    performSearch(debouncedQuery, true);
  }, [debouncedQuery, performSearch]);

  const handleManualSearch = (e: React.FormEvent) => {
    e.preventDefault();
    performSearch(query, false); // false = force search
  };

  const openChatWithContext = (repo: GitHubRepo) => {
    setChatContext(repo);
