export const enhanceSearchQuery = async (query: string): Promise<string> => {
  if (!apiKey) return query;

  const prompt = `
    You are an intelligent search query corrector for a GitHub repository search engine.

    User Input: "${query}"

    Your tasks:
    1.  **CORRECT TYPOS**: This is your primary priority. If the user types "reacct" -> "react", "pyton" -> "python", "javascriptt" -> "javascript".
