import RepoCard from './components/RepoCard';
import FilterBar from './components/FilterBar';
import AIChat from './components/AIChat';

const HISTORY_KEY = 'gitscout_search_history';

// Helper hook for debouncing values
function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState(value);
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);
    return () => clearTimeout(handler);
  }, [value, delay]);
  return debouncedValue;
}

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebounce(query, 1000); // 1s delay for AI/API optimization

  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [optimizedQuery, setOptimizedQuery] = useState('');
  const [filters, setFilters] = useState<FilterState>({
    language: '',
    sort: 'best-match', // Default to Google-like relevance
    minStars: 0,
  });

  // Search History State
  const [searchHistory, setSearchHistory] = useState<string[]>(() => {
    if (typeof window === 'undefined') return [];
    try {
      const saved = localStorage.getItem(HISTORY_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error(e);
      return [];
    }
  });

  // Track last search to avoid duplicates
  const lastSearchRef = useRef({ query: '', filters: '' });
  // Track current request ID to handle race conditions
  const searchIdRef = useRef(0);

  // Chat state
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatContext, setChatContext] = useState<GitHubRepo | null>(null);

  const addToHistory = (q: string) => {
    const trimmed = q.trim();
    if (!trimmed) return;
    setSearchHistory(prev => {
      // Remove duplicates and keep mostly recent
      const filtered = prev.filter(item => item.toLowerCase() !== trimmed.toLowerCase());
      const newHistory = [trimmed, ...filtered].slice(0, 5); // Keep top 5
      localStorage.setItem(HISTORY_KEY, JSON.stringify(newHistory));
      return newHistory;
    });
  };

  const removeFromHistory = (e: React.MouseEvent, itemToRemove: string) => {
    e.stopPropagation();
    setSearchHistory(prev => {
      const newHistory = prev.filter(item => item !== itemToRemove);
      localStorage.setItem(HISTORY_KEY, JSON.stringify(newHistory));
      return newHistory;
    });
  };

  const clearHistory = () => {
    setSearchHistory([]);
    localStorage.removeItem(HISTORY_KEY);
  };

  const performSearch = useCallback(async (searchQueryRaw: string, isAuto: boolean = false) => {
    // CRITICAL: Strictly trim the query here to handle "react " vs "react"
    const searchQuery = searchQueryRaw.trim();

    // Clear results if query is empty
    if (!searchQuery) {
      setRepos([]);
      setError('');
      setOptimizedQuery('');
      return;
    }

    const currentFiltersStr = JSON.stringify(filters);

    // Prevent duplicate auto-searches
    if (isAuto && 
        searchQuery === lastSearchRef.current.query && 
        currentFiltersStr === lastSearchRef.current.filters) {
      return;
    }

    // Update ref for duplicate check
    lastSearchRef.current = { 
      query: searchQuery, 
      filters: currentFiltersStr 
    };

    // Increment request ID to invalidate previous pending requests
    const requestId = ++searchIdRef.current;

    setLoading(true);
    setError('');
    setOptimizedQuery('');

    try {
      let finalQuery = searchQuery;

      // Always try to enhance query (fix typos & add semantic meaning) silently
      try {
        finalQuery = await enhanceSearchQuery(searchQuery);

        // If a new request started while we were enhancing, stop here
        if (requestId !== searchIdRef.current) return;

        console.log(`Optimized Search: "${searchQuery}" -> "${finalQuery}"`);

        // If the query was significantly changed, show it to the user
        if (finalQuery.toLowerCase() !== searchQuery.toLowerCase()) {
            setOptimizedQuery(finalQuery);
        }

      } catch (err) {
        console.error("Optimization failed, using original query");
      }

      // Check staleness before calling GitHub API
      if (requestId !== searchIdRef.current) return;

      const data = await searchRepositories(finalQuery, filters);

      // Check staleness after GitHub API call
      if (requestId !== searchIdRef.current) return;

      setRepos(data);
      if (data.length === 0) setError(`No repositories found matching "${finalQuery}".`);
    } catch (err: any) {
      // Check staleness before updating error
      if (requestId !== searchIdRef.current) return;

      setError(err.message || 'Failed to fetch repositories. Please try again later.');
    } finally {
      // Only turn off loading if this is the active request
      if (requestId === searchIdRef.current) {
        setLoading(false);
      }
    }
  }, [filters]);

  // Effect for auto-search when debounced query or filters change
  useEffect(() => {
    performSearch(debouncedQuery, true);
  }, [debouncedQuery, performSearch]);

  const handleManualSearch = (e: React.FormEvent) => {
    e.preventDefault();
    addToHistory(query);
    performSearch(query, false); // false = force search
  };

  const handleHistoryClick = (historyItem: string) => {
    setQuery(historyItem);
    addToHistory(historyItem); // Move to top
    performSearch(historyItem, false);
  };

  const handleRetry = () => {
    performSearch(query, false);
  };

  const openChatWithContext = (repo: GitHubRepo) => {
    setChatContext(repo);
    setIsChatOpen(true);
  };

  return (
    <div className="min-h-screen bg-background text-slate-200 pb-20 relative">
      {/* Navbar */}
      <nav className="border-b border-slate-800 bg-surface/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Github className="text-white" size={28} />
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-500 text-transparent bg-clip-text">
              GitScout
            </h1>
          </div>
          <button 
            onClick={() => { setChatContext(null); setIsChatOpen(true); }}
            className="text-sm font-medium text-slate-300 hover:text-white transition-colors flex items-center gap-2"
          >
             GitScout Assistant
          </button>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Hero / Search Section */}
        <div className="text-center mb-10 space-y-4">
          <h2 className="text-4xl font-black text-white tracking-tight sm:text-5xl">
            Find & Analyze <br />
            <span className="text-blue-500">GitHub Repositories</span>
          </h2>
          <p className="text-slate-400 max-w-2xl mx-auto text-lg">
            Search for any library, framework, or tool. Our AI rates them for you and helps you debug.
          </p>

          <form onSubmit={handleManualSearch} className="max-w-2xl mx-auto mt-8 relative group">
            <div className="relative">
              <input 
                type="text" 
                placeholder="Search for repositories (e.g., 'how to make a website', 'auth for node')"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-surface border border-slate-700 text-white rounded-2xl py-4 pl-12 pr-4 shadow-xl focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all text-lg placeholder:text-slate-500"
              />
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={24} />
              <button 
                type="submit"
                disabled={loading}
                className="absolute right-2 top-2 bottom-2 bg-blue-600 hover:bg-blue-500 disabled:bg-blue-600/50 text-white px-6 rounded-xl font-medium transition-colors flex items-center gap-2"
              >
                {loading ? (
                  <Loader2 className="animate-spin" size={20} />
                ) : (
                  "Search"
                )}
              </button>
            </div>
          </form>

          {/* Search History */}
          {searchHistory.length > 0 && (
            <div className="flex flex-wrap items-center justify-center gap-2 mt-4 animate-in fade-in slide-in-from-top-1 duration-300">
               <div className="flex items-center gap-1.5 text-xs text-slate-500 mr-1 select-none">
                 <History size={12} />
                 <span>Recent:</span>
               </div>
               {searchHistory.map((term) => (
                 <button
                   key={term}
                   onClick={() => handleHistoryClick(term)}
                   className="group flex items-center gap-1.5 px-3 py-1 bg-surface border border-slate-700/50 hover:border-blue-500/50 hover:bg-blue-500/10 rounded-full text-xs text-slate-400 hover:text-blue-300 transition-all cursor-pointer"
                 >
                   <span className="max-w-[150px] truncate">{term}</span>
                   <span 
                     onClick={(e) => removeFromHistory(e, term)}
                     className="opacity-0 group-hover:opacity-100 p-0.5 hover:bg-slate-700 rounded-full hover:text-red-400 text-slate-500 transition-all"
                     title="Remove from history"
                   >
                     <X size={10} />
                   </span>
                 </button>
               ))}
               <button 
                 onClick={clearHistory}
                 className="text-[10px] text-slate-600 hover:text-red-400 underline decoration-slate-700 underline-offset-2 ml-2 transition-colors"
               >
                 Clear
               </button>
            </div>
          )}
        </div>

        {/* Filters */}
        <div className="max-w-7xl mx-auto mt-12">
          <FilterBar filters={filters} onChange={setFilters} />
        </div>

        {/* Smart Search Feedback */}
        {optimizedQuery && !loading && !error && (
            <div className="max-w-7xl mx-auto mb-6 px-4">
                <div className="flex items-center gap-2 text-sm bg-blue-500/10 border border-blue-500/20 text-blue-300 p-3 rounded-lg w-fit">
                    <Sparkles size={16} className="text-blue-400" />
                    <span>Searching for <strong>"{optimizedQuery}"</strong> instead of "{query.trim()}"</span>
                </div>
            </div>
        )}

        {/* Content Area */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Loader2 size={48} className="animate-spin mb-4 text-blue-500" />
            <p>Scouting repositories...</p>
          </div>
        ) : error ? (
          <div className="text-center py-20 text-red-400 bg-red-900/10 rounded-xl border border-red-900/50 flex flex-col items-center gap-4">
            <p>{error}</p>
            <button 
              onClick={handleRetry}
              className="bg-red-900/40 hover:bg-red-900/60 text-red-200 px-4 py-2 rounded-lg flex items-center gap-2 transition-colors"
            >
              <RefreshCw size={16} /> Try Again
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {repos.map((repo) => (
              <RepoCard 
                key={repo.id} 
                repo={repo} 
                onSelectForChat={openChatWithContext}
              />
            ))}
          </div>
        )}

        {!loading && repos.length === 0 && !error && (
          <div className="text-center py-20 text-slate-500">
            <p>{query ? "No repositories found." : "Enter a keyword above to start scouting."}</p>
          </div>
        )}
      </main>

      {/* AI Chat Widget */}
      <AIChat 
        isOpen={isChatOpen} 
        onClose={() => setIsChatOpen(false)} 
        contextRepo={chatContext}
      />
    </div>
  );
};

