import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, Minimize2, Trash2, Code2 } from 'lucide-react';
import { ChatMessage, GitHubRepo } from '../types';
import { getChatResponse } from '../services/geminiService';

interface AIChatProps {
  isOpen: boolean;
  onClose: () => void;
  contextRepos: GitHubRepo[];
  onRemoveRepo: (repoId: number) => void;
}

const STORAGE_KEY = 'gitscout_chat_history';

const AIChat: React.FC<AIChatProps> = ({ isOpen, onClose, contextRepos, onRemoveRepo }) => {
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (e) {
      console.error("Failed to parse chat history", e);
    }
    return [{ role: 'model', text: 'Hi! I can help you understand repos, debug issues, or explain code. Select repositories to get specific help!', timestamp: Date.now() }];
  });

  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const prevContextRef = useRef<string>('');

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen, isMinimized]);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  // Notify user when context changes
  useEffect(() => {
    if (contextRepos.length > 0) {
      const contextIds = contextRepos.map(r => r.id).sort().join(',');

      if (prevContextRef.current !== contextIds) {
        const names = contextRepos.map(r => r.name).join(', ');
        const contextMsg = `I see you're interested in: **${names}**. How can I help you compare or analyze these?`;

        setMessages(prev => {
           const lastMsg = prev[prev.length - 1];
           if (lastMsg?.text === contextMsg) return prev;
           return [...prev, { role: 'model', text: contextMsg, timestamp: Date.now() }];
        });

        if (isMinimized) setIsMinimized(false);
        prevContextRef.current = contextIds;
      }
    }
  }, [contextRepos]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const response = await getChatResponse(userMsg.text, contextRepos);
      setMessages(prev => [...prev, { role: 'model', text: response, timestamp: Date.now() }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Sorry, I encountered an error.", timestamp: Date.now() }]);
    } finally {
      setLoading(false);
    }
  };

  const clearChat = () => {
    if (window.confirm("Are you sure you want to clear the chat history?")) {
      const initialMsg: ChatMessage = { role: 'model', text: 'Chat history cleared. How can I help you?', timestamp: Date.now() };
      setMessages([initialMsg]);
      localStorage.setItem(STORAGE_KEY, JSON.stringify([initialMsg]));
    }
  };

  if (!isOpen) return null;

  if (isMinimized) {
    return (
      <button
        onClick={() => setIsMinimized(false)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full shadow-xl flex items-center justify-center text-white z-50 transition-all hover:scale-110"
      >
        <Bot size={28} />
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-[90vw] md:w-[400px] h-[600px] max-h-[80vh] bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl flex flex-col overflow-hidden z-50 animate-in slide-in-from-bottom-10 fade-in duration-300">
      {/* Header */}
      <div className="bg-slate-800 p-4 flex justify-between items-center border-b border-slate-700">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
            <Bot size={18} className="text-white" />
          </div>
          <div>
            <h3 className="font-bold text-slate-100">GitScout</h3>
            <p className="text-[10px] text-slate-400 flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
              Online
            </p>
          </div>
        </div>
        <div className="flex items-center gap-1 text-slate-400">
          <button 
            onClick={clearChat} 
            className="p-1.5 hover:bg-slate-700 rounded transition-colors hover:text-red-400"
            title="Clear Chat History"
          >
            <Trash2 size={16} />
          </button>
          <button onClick={() => setIsMinimized(true)} className="p-1.5 hover:bg-slate-700 rounded transition-colors">
            <Minimize2 size={16} />
          </button>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-700 rounded transition-colors hover:text-red-400">
            <X size={16} />
          </button>
        </div>
      </div>

      {/* Context Banner */}
      {contextRepos.length > 0 && (
        <div className="bg-slate-800/50 px-3 py-2 border-b border-slate-700 flex flex-col gap-1">
           <div className="flex items-center gap-2 text-xs text-blue-300 mb-1">
             <Code2 size={12} />
             <span className="font-semibold">Context ({contextRepos.length})</span>
           </div>
           <div className="flex flex-wrap gap-2 max-h-[80px] overflow-y-auto custom-scrollbar">
             {contextRepos.map(repo => (
               <div key={repo.id} className="flex items-center gap-1 bg-blue-900/40 border border-blue-500/30 text-blue-200 text-[10px] px-2 py-1 rounded-full">
                 <span className="truncate max-w-[150px]">{repo.name}</span>
                 <button 
                   onClick={() => onRemoveRepo(repo.id)}
                   className="hover:text-red-300 transition-colors"
                 >
                   <X size={10} />
                 </button>
               </div>
             ))}
           </div>
        </div>
      )}

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/95">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : 'bg-slate-800 text-slate-200 rounded-bl-none border border-slate-700'
              }`}
            >
              <div className="whitespace-pre-wrap">{msg.text}</div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-slate-800 rounded-2xl rounded-bl-none px-4 py-3 border border-slate-700 flex items-center gap-2">
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-slate-800 border-t border-slate-700">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={contextRepos.length > 0 ? "Ask about these repos..." : "Ask for debugging help..."}
            className="flex-1 bg-slate-900 border border-slate-600 text-slate-200 text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-blue-500 transition-colors"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || loading}
            className="bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-xl disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

