];

export const enhanceSearchQuery = async (query: string): Promise<string> => {
  if (!apiKey) return query;

  // Skip enhancement if user is using advanced search syntax or explicitly filtering by ID-like patterns
  if (query.includes('user:') || query.includes('org:') || query.includes('repo:') || query.includes('topic:')) {
    return query;
  }

  const prompt = `
    You are GitScout's Search Intelligence Engine. Your goal is to construct the MOST EFFECTIVE GitHub Search API query string based on the user's intent.

    User Input: "${query}"

    CRITICAL RULES for GitHub Search Syntax:
    1.  **Default is AND**: GitHub treats "react native" as "react AND native".
    2.  **Use OR for synonyms**: Use parentheses and OR for variations. E.g., "(todo OR task-manager)".
    3.  **Phrase Matching**: Use quotes for specific phrases. E.g., "\"machine learning\"".
    4.  **Field Targeting**: Use \`in:name,description,topics\` to search relevant fields and avoid noise from code comments.
    5.  **Topic Expansion**: If the query is a technology, add \`topic:tech\`. E.g., "(react OR topic:react)".
    6.  **Do NOT add sort/language/stars**: These are handled by UI filters.

    Examples:
    - Input: "make a website" 
      -> Output: \`("website starter" OR "web boilerplate" OR "website template") in:name,description,topics\`

    - Input: "python script for scraping" 
      -> Output: \`("web scraping" OR scraper OR "data extraction") language:python in:name,description,topics\`
      *(Note: Adding language:python here is okay if it reinforces intent, but UI filter is primary. Prefer leaving language to UI if ambiguous, but for specific "python script" requests, it's helpful.)*

    - Input: "react"
      -> Output: \`(react OR topic:react) in:name,description,topics\`

    - Input: "linux kernel"
      -> Output: \`"linux kernel" in:name,description,topics\`

    Output ONLY the query string.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        safetySettings,
      }
    });
    const text = response.text?.trim();
    // Fallback if AI returns something weird or empty
    return text || query;
  } catch (error) {
    console.error("Query enhancement failed", error);
    return query;
  }
};

