import { GitHubRepo, FilterState } from '../types';

const BASE_URL = 'https://api.github.com/search/repositories';

export const searchRepositories = async (
  query: string,
  filters: FilterState
): Promise<GitHubRepo[]> => {
  // If query is empty but we have an owner, we can search by owner
  if (!query.trim() && !filters.owner) return [];

  // Construct query string
  let q = query;

  if (filters.owner) {
    // If the user typed "org:name" or "user:name" directly in the filter box, use it as is.
    // Otherwise, default to "user:" which covers both users and organizations for ownership.
    const ownerVal = filters.owner.trim();
    if (ownerVal.includes(':')) {
       q += ` ${ownerVal}`;
    } else {
       q += ` user:${ownerVal}`;
    }
  }

  if (filters.language) {
    q += ` language:${filters.language}`;
  }
  if (filters.minStars > 0) {
    q += ` stars:>=${filters.minStars}`;
  }

  const queryParams: Record<string, string> = {
    q: q.trim(),
    order: 'desc',
    per_page: '30',
  };

  // GitHub API uses "best match" when 'sort' is omitted.
  // Only add sort param if it's NOT best-match
  if (filters.sort !== 'best-match') {
    queryParams.sort = filters.sort;
  }

  const params = new URLSearchParams(queryParams);

  try {
    const response = await fetch(`${BASE_URL}?${params.toString()}`, {
      headers: {
        'Accept': 'application/vnd.github.v3+json',
      }
    });

    if (!response.ok) {
      if (response.status === 403) {
        throw new Error("GitHub API rate limit exceeded. Please wait a moment or try again later.");
      }
      if (response.status === 422) {
        throw new Error("Invalid search query. Please try different keywords.");
      }
      throw new Error(`GitHub API Error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json();
    return data.items || [];
  } catch (error) {
    console.error('Failed to fetch repositories:', error);
    throw error;
  }
};

