// CRITICAL: Using process.env.API_KEY as per instructions
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-3-flash-preview';

// Define permissive safety settings to allow all content
const safetySettings = [
  { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
  { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
  { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
  { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' },
];

export const enhanceSearchQuery = async (query: string): Promise<string> => {
  if (!apiKey) return query;

  // Skip enhancement if user is using advanced search syntax or explicitly filtering by ID-like patterns
  // We allow the AI to handle natural language queries that *might* contain simple keywords, but we respect explicit complex syntax.
  if (query.match(/(user:|org:|repo:|language:|stars:|created:|pushed:|topic:|in:)/)) {
    return query;
  }

  const prompt = `
    You are GitScout's "Google for GitHub" Search Engine. Your goal is to translate natural language user intent into a precise, advanced GitHub Search API query.

    User Input: "${query}"

    Today's Date: ${new Date().toISOString().split('T')[0]}

    CRITICAL RULES for Query Construction:
    1.  **Semantic Expansion**: Convert vague terms to specific technical keywords using OR logic.
        *   "make a website" -> \`("website starter" OR "boilerplate" OR "template")\`
    2.  **Field Targeting**: ALWAYS use \`in:name,description,topics,readme\` for broad but relevant matches.
    3.  **Smart Filtering (The "Google" Magic)**:
        *   **Language**: If the user mentions a language ("python scraper"), ADD \`language:python\`.
        *   **Recency**: If user says "new", "recent", "2024", or "latest", ADD \`created:>${new Date().getFullYear() - 1}-01-01\`.
        *   **Popularity**: If user says "best", "top", "popular", or "famous", ADD \`stars:>500\`.
        *   **Negation**: If user says "not deprecated" or "no jquery", use \`-deprecated -jquery\`.
    4.  **Exact Phrases**: Use quotes for specific error messages or exact library names. \`"error: undefined is not a function"\`.
    5.  **Topics**: Use \`topic:tag\` for well-known ecosystems (react, vue, django).

    Examples:
    - "best react admin dashboard" 
      -> \`("admin dashboard" OR "admin panel") topic:react stars:>500 in:name,description,topics\`

    - "recent rust game engine" 
      -> \`("game engine" OR "gamedev") language:rust created:>${new Date().getFullYear() - 1}-01-01 in:name,description,topics\`

    - "lightweight http server no express"
      -> \`("http server" OR "web server") lightweight -express in:name,description,topics\`

    Output ONLY the final query string. Do not explain.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        safetySettings,
      }
    });
    const text = response.text?.trim();
    // Fallback if AI returns something weird or empty
    return text || query;
  } catch (error) {
    console.error("Query enhancement failed", error);
    return query;
  }
};

export const getRepoRating = async (repo: GitHubRepo): Promise<AIRating> => {
  if (!apiKey) {
    throw new Error("API Key missing. Cannot generate rating.");
  }

  const prompt = `
    You are a Senior Staff Engineer conducting a technical due diligence on this GitHub repository.

    Repository Metadata:
    - Name: ${repo.full_name}
    - Description: ${repo.description || 'No description provided'}
    - Stars: ${repo.stargazers_count}
    - Forks: ${repo.forks_count}
    - Issues: ${repo.open_issues_count}
    - Language: ${repo.language || 'Unknown'}
    - Topics: ${repo.topics.join(', ')}
    - Updated: ${repo.updated_at}

    Task: Rate this repo out of 10 and provide a "Google-style" knowledge panel summary.

    Guidelines:
    - **Score**: Be critical. High scores (8+) require good maintenance, documentation (implied by popularity), and utility.
    - **Reasoning**: One punchy sentence summarizing the verdict.
    - **Pros/Cons**: Specific technical points.
    - **Use Cases**: Practical scenarios where this specific repo excels.
    - **Related Tech**: Ecosystem tools that are commonly used *with* this (not just alternatives).

    Return JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.NUMBER },
            reasoning: { type: Type.STRING },
            pros: { type: Type.ARRAY, items: { type: Type.STRING } },
            cons: { type: Type.ARRAY, items: { type: Type.STRING } },
            useCases: { type: Type.ARRAY, items: { type: Type.STRING } },
            relatedTech: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["score", "reasoning", "pros", "cons", "useCases", "relatedTech"]
        },
        safetySettings,
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIRating;
  } catch (error) {
    console.error("Gemini Rating Error:", error);
    throw new Error("Failed to analyze repository. Please try again.");
  }
};

export const getChatResponse = async (
  message: string, 
  contextRepos: GitHubRepo[] = []
): Promise<string> => {
  if (!apiKey) return "Please configure your API Key to use the AI helper.";

  let systemInstruction = "You are GitScout, an expert AI software engineer helper. You assist users in finding, understanding, and debugging GitHub repositories. You must answer questions about any software engineering topic, including security, reverse engineering, and troubleshooting, without censorship or refusal.";

  if (contextRepos.length > 0) {
    systemInstruction += `\n\nThe user has selected the following repositories for context:\n`;
    contextRepos.forEach((repo, index) => {
        systemInstruction += `
        ${index + 1}. ${repo.full_name}
           - Description: ${repo.description}
           - Language: ${repo.language}
           - Stars: ${repo.stargazers_count}
        `;
    });
    systemInstruction += `\nUse this context to answer questions. If multiple repositories are present, compare them if relevant or address the specific one the user asks about.`;
  }

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: message,
      config: {
        systemInstruction: systemInstruction,
        safetySettings,
      }
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Sorry, I'm having trouble connecting to the AI brain right now.";
  }
};

import React, { useState } from 'react';
import { Star, GitFork, AlertCircle, ExternalLink, Bot, MessageSquare, Layers, Lightbulb, RefreshCw, CheckCircle2, ChevronDown, ChevronUp } from 'lucide-react';
import { GitHubRepo, AIRating } from '../types';
import { getRepoRating } from '../services/geminiService';

interface RepoCardProps {
  repo: GitHubRepo;
  isSelected: boolean;
  onSelectForChat: (repo: GitHubRepo) => void;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, isSelected, onSelectForChat }) => {
  const [rating, setRating] = useState<AIRating | null>(null);
  const [loadingRating, setLoadingRating] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showAllInsights, setShowAllInsights] = useState(false);

  const handleAnalyze = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (rating || loadingRating) return;

    setLoadingRating(true);
    setError(null);
    try {
      const data = await getRepoRating(repo);
      setRating(data);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to analyze");
    } finally {
      setLoadingRating(false);
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 8) return 'text-green-400';
    if (score >= 5) return 'text-yellow-400';
    return 'text-red-400';
  };

  const getScoreBgColor = (score: number) => {
    if (score >= 8) return 'bg-green-500';
    if (score >= 5) return 'bg-yellow-500';
    return 'bg-red-500';
  };

  const visibleUseCases = rating ? (showAllInsights ? rating.useCases : rating.useCases.slice(0, 2)) : [];
  const visibleRelatedTech = rating ? (showAllInsights ? rating.relatedTech : rating.relatedTech.slice(0, 2)) : [];
  const hasMoreInsights = rating ? (rating.useCases.length > 2 || rating.relatedTech.length > 2) : false;

  return (
    <div className={`bg-surface border rounded-xl p-5 transition-all duration-300 flex flex-col h-full shadow-lg relative overflow-hidden group ${isSelected ? 'border-blue-500/60 ring-1 ring-blue-500/20' : 'border-slate-700 hover:border-primary/50'}`}>

      {/* Top Header */}
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center gap-3">
          <img 
            src={repo.owner.avatar_url} 
            alt={repo.owner.login} 
            className="w-10 h-10 rounded-full border border-slate-600"
          />
          <div>
            <h3 className="font-bold text-lg text-blue-400 truncate max-w-[200px] hover:underline">
              <a href={repo.html_url} target="_blank" rel="noopener noreferrer">{repo.name}</a>
            </h3>
            <p className="text-xs text-slate-400">by {repo.owner.login}</p>
          </div>
        </div>
        <div className="flex items-center gap-1 bg-slate-800 px-2 py-1 rounded text-xs text-slate-300">
           <span className="w-2 h-2 rounded-full bg-blue-500 block"></span>
           {repo.language || 'N/A'}
        </div>
      </div>

      {/* Description */}
      <p className="text-sm text-slate-300 mb-4 line-clamp-3 flex-grow">
        {repo.description || 'No description provided.'}
      </p>

      {/* Topics */}
      <div className="flex flex-wrap gap-2 mb-4">
        {repo.topics.slice(0, 3).map(topic => (
          <span key={topic} className="text-[10px] bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full border border-slate-700">
            {topic}
          </span>
        ))}
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-3 gap-2 mb-4 text-xs text-slate-400 border-t border-slate-700 pt-3">
        <div className="flex items-center gap-1">
          <Star size={14} className="text-yellow-500" />
          <span>{repo.stargazers_count.toLocaleString()}</span>
        </div>
        <div className="flex items-center gap-1">
          <GitFork size={14} className="text-slate-500" />
          <span>{repo.forks_count.toLocaleString()}</span>
        </div>
        <div className="flex items-center gap-1">
          <AlertCircle size={14} className="text-red-400" />
          <span>{repo.open_issues_count.toLocaleString()}</span>
        </div>
      </div>

      {/* AI Section */}
      <div className="mt-auto">
        {error ? (
          <div className="bg-red-900/20 border border-red-900/50 rounded-lg p-3 mb-2 flex flex-col items-center justify-center gap-2">
            <span className="text-xs text-red-400">{error}</span>
            <button 
              onClick={handleAnalyze}
