  };

  return (
    <div className="bg-surface border border-border rounded-xl p-5 hover:border-primary/50 transition-all flex flex-col h-full group relative overflow-hidden">

      {/* Header */}
      <div className="flex justify-between items-start mb-3">
        <div className="flex items-center gap-3">
          <img src={repo.owner.avatar_url} alt="Owner" className="w-10 h-10 rounded-full border border-border" />
          <div>
            <a href={repo.html_url} target="_blank" rel="noreferrer" className="font-bold text-lg text-primary hover:underline line-clamp-1">
              {repo.name}
            </a>
            <p className="text-xs text-secondary">{repo.owner.login}</p>
          </div>
        </div>
        <div className="flex flex-col items-end gap-1">
          {repo.language && (
             <span className="text-[10px] uppercase tracking-wider font-bold text-secondary bg-background px-2 py-1 rounded-full border border-border">
               {repo.language}
             </span>
          )}
        </div>
      </div>

      {/* Description */}
      <p className="text-sm text-slate-300 mb-4 line-clamp-3 flex-grow">
        {repo.description || "No description provided by the author."}
      </p>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-2 text-xs text-secondary border-t border-border pt-3 mb-4">
        <div className="flex items-center gap-1"><Star size={14} className="text-yellow-500" /> {repo.stargazers_count}</div>
        <div className="flex items-center gap-1"><GitFork size={14} /> {repo.forks_count}</div>
        <div className="flex items-center gap-1"><AlertCircle size={14} /> {repo.open_issues_count}</div>
        <div className="flex items-center gap-1"><Eye size={14} /> {repo.watchers_count}</div>
      </div>

      {/* AI Rating Section */}
      {!rating ? (
        <button 
          onClick={handleRate}
          disabled={loading}
          className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 text-xs font-semibold rounded-lg flex items-center justify-center gap-2 transition-all border border-border"
        >
          {loading ? <Loader2 size={16} className="animate-spin" /> : <Sparkles size={16} />}
          {loading ? "Analyzing..." : "AI Rate & Review"}
        </button>
      ) : (
        <div className="bg-background rounded-lg p-3 border border-border animate-in fade-in slide-in-from-bottom-2 duration-300">
          <div className="flex justify-between items-end mb-2">
            <span className="text-xs font-bold text-slate-400">GitScout Score</span>
            <span className={`text-xl font-black ${rating.score >= 8 ? 'text-green-400' : rating.score >= 5 ? 'text-yellow-400' : 'text-red-400'}`}>
              {rating.score}<span className="text-xs text-slate-600">/10</span>
            </span>
          </div>

          <p className="text-xs italic text-slate-400 mb-3 border-b border-border pb-2">"{rating.summary}"</p>

          <div className="grid grid-cols-2 gap-2 mb-2">
            <div>
              <p className="text-[10px] font-bold text-green-500 uppercase">Pros</p>
              <ul className="text-[10px] text-secondary list-disc pl-3">
                {rating.pros.slice(0, 2).map((p, i) => <li key={i}>{p}</li>)}
              </ul>
            </div>
            <div>
              <p className="text-[10px] font-bold text-red-500 uppercase">Cons</p>
              <ul className="text-[10px] text-secondary list-disc pl-3">
                {rating.cons.slice(0, 2).map((c, i) => <li key={i}>{c}</li>)}
              </ul>
            </div>
          </div>

          {/* Expandable Section */}
          {(rating.useCases.length > 0 || rating.relatedTech.length > 0) && (
            <div className="mt-2">
               {expanded && (
                 <div className="pt-2 border-t border-border space-y-2 mb-2">
                    <div>
                      <p className="text-[10px] font-bold text-blue-400 mb-1">Use Cases</p>
                      <div className="flex flex-wrap gap-1">
                        {rating.useCases.map((u, i) => (
                          <span key={i} className="px-1.5 py-0.5 bg-blue-900/20 text-blue-200 text-[10px] rounded border border-blue-900/30">{u}</span>
                        ))}
                      </div>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-purple-400 mb-1">Related Tech</p>
                      <div className="flex flex-wrap gap-1">
                        {rating.relatedTech.map((t, i) => (
                          <span key={i} className="px-1.5 py-0.5 bg-purple-900/20 text-purple-200 text-[10px] rounded border border-purple-900/30">{t}</span>
                        ))}
                      </div>
                    </div>
                 </div>
               )}
               <button 
                onClick={() => setExpanded(!expanded)}
                className="w-full text-[10px] text-secondary hover:text-primary flex items-center justify-center gap-1 pt-1"
               >
                 {expanded ? <>Show Less <ChevronUp size={12}/></> : <>Deep Dive <ChevronDown size={12}/></>}
               </button>
            </div>
          )}
        </div>
      )}

      {/* Actions */}
      <div className="mt-3 flex gap-2">
        <button 
          onClick={() => onChatContext(repo)}
          className="flex-1 py-1.5 bg-primary/10 hover:bg-primary/20 text-primary border border-primary/30 rounded text-xs font-medium flex items-center justify-center gap-2 transition-all"
        >
          <MessageSquare size={14} /> Chat
        </button>
        <a 
          href={repo.html_url} 
          target="_blank" 
          rel="noreferrer"
          className="py-1.5 px-3 bg-surface hover:bg-slate-800 text-secondary border border-border rounded text-xs flex items-center justify-center"
        >
          <ExternalLink size={14} />
        </a>
      </div>
    </div>
  );
};

export default RepoCard;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Bot, Minimize2 } from 'lucide-react';
import { ChatMessage, GitHubRepo } from '../types';
import { sendChatMessage } from '../services/geminiService';

interface ChatAssistantProps {
  contextRepo: GitHubRepo | null;
  onClearContext: () => void;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ contextRepo, onClearContext }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: 'init', role: 'model', content: 'Hi! I can help you debug code or find the perfect repo. Ask me anything!', timestamp: Date.now() }
  ]);
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-open if context is added
  useEffect(() => {
    if (contextRepo) {
      setIsOpen(true);
      setIsMinimized(false);
      setMessages(prev => [
        ...prev, 
        { 
          id: Date.now().toString(), 
          role: 'model', 
          content: `I see you're looking at **${contextRepo.full_name}**. Need help installing it or understanding the code?`, 
          timestamp: Date.now() 
        }
      ]);
    }
  }, [contextRepo]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    let contextStr = "";
    if (contextRepo) {
      contextStr = `Repository: ${contextRepo.full_name}\nDescription: ${contextRepo.description}\nLanguage: ${contextRepo.language}\nStars: ${contextRepo.stargazers_count}`;
    }

    try {
      const responseText = await sendChatMessage(
        messages.concat(userMsg).map(m => ({ role: m.role, content: m.content })),
        contextStr
      );
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: responseText, timestamp: Date.now() }]);
    } catch (e) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Sorry, connection error.", timestamp: Date.now() }]);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-primary hover:bg-blue-600 text-white rounded-full shadow-2xl flex items-center justify-center transition-all hover:scale-110 z-50"
      >
        <MessageCircle size={28} />
      </button>
    );
  }

  if (isMinimized) {
    return (
      <div className="fixed bottom-6 right-6 w-72 bg-surface border border-border rounded-t-xl shadow-2xl z-50">
        <div className="p-3 bg-slate-900 rounded-t-xl flex justify-between items-center cursor-pointer" onClick={() => setIsMinimized(false)}>
          <div className="flex items-center gap-2 text-sm font-bold text-white">
            <Bot size={18} className="text-primary" /> GitScout Assistant
          </div>
          <button onClick={(e) => { e.stopPropagation(); setIsOpen(false); }}><X size={16} className="text-slate-400 hover:text-white" /></button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-[90vw] md:w-[400px] h-[600px] max-h-[80vh] bg-surface border border-border rounded-xl shadow-2xl flex flex-col z-50 animate-in slide-in-from-bottom-10 fade-in duration-300">

      {/* Header */}
      <div className="p-4 bg-slate-900 border-b border-border rounded-t-xl flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center border border-primary/50">
            <Bot size={18} className="text-primary" />
          </div>
          <div>
            <h3 className="font-bold text-white text-sm">GitScout Assistant</h3>
            <p className="text-[10px] text-green-400 flex items-center gap-1"><span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> Online</p>
          </div>
        </div>
        <div className="flex gap-2 text-slate-400">
          <button onClick={() => setIsMinimized(true)} className="hover:text-white"><Minimize2 size={18} /></button>
          <button onClick={() => setIsOpen(false)} className="hover:text-red-400"><X size={18} /></button>
        </div>
      </div>

      {/* Context Banner */}
      {contextRepo && (
        <div className="px-4 py-2 bg-primary/10 border-b border-primary/20 flex justify-between items-center">
          <span className="text-xs text-primary font-medium truncate max-w-[250px]">Context: {contextRepo.name}</span>
          <button onClick={onClearContext} className="text-xs text-slate-500 hover:text-white"><X size={12}/></button>
        </div>
      )}

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-background/50" ref={scrollRef}>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
              msg.role === 'user' 
                ? 'bg-primary text-white rounded-br-none' 
                : 'bg-surface border border-border text-slate-200 rounded-bl-none'
            }`}>
              <p className="whitespace-pre-wrap">{msg.content}</p>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="bg-surface border border-border rounded-2xl rounded-bl-none px-4 py-3 flex gap-1">
               <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
               <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:0.1s]"></span>
               <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
             </div>
          </div>
        )}
      </div>

      {/* Input */}
      <div className="p-4 bg-surface border-t border-border">
        <div className="flex gap-2">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask a question..."
            className="flex-1 bg-background border border-border rounded-lg px-4 py-2 text-sm text-white focus:outline-none focus:border-primary"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || loading}
            className="bg-primary hover:bg-blue-600 disabled:opacity-50 text-white p-2 rounded-lg transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatAssistant;

import React, { useState, useRef, useEffect } from 'react';
import { Search, Loader2, Sparkles, SlidersHorizontal, Github, ArrowRight } from 'lucide-react';
import { GitHubRepo, SearchFilters } from './types';
import { optimizeSearchQuery } from './services/geminiService';
import { searchGitHub } from './services/githubService';
import RepoCard from './components/RepoCard';
import ChatAssistant from './components/ChatAssistant';

const App: React.FC = () => {
  // State
  const [query, setQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false); // UI state for search bar position
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<GitHubRepo[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [error, setError] = useState('');
  const [optimizedQuery, setOptimizedQuery] = useState('');
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [activeChatRepo, setActiveChatRepo] = useState<GitHubRepo | null>(null);

  // Filters
  const [filters, setFilters] = useState<SearchFilters>({
    language: '',
    minStars: 0,
    sort: 'best-match',
    order: 'desc'
  });

  // Race Condition Handling
  const requestIdRef = useRef(0);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim()) return;

    setIsSearching(true);
    setLoading(true);
    setError('');
    setOptimizedQuery('');

    // Increment request ID
    const currentId = ++requestIdRef.current;

    try {
      // Step 1: Optimize Query with AI (The Google-like part)
      // We do this in parallel with a slight delay to the UI to show "Thinking..."
      let finalQuery = query;
      try {
        finalQuery = await optimizeSearchQuery(query);
      } catch (err) {
        console.warn("Optimization failed, using raw query");
      }

      // If a new search started, abort
      if (currentId !== requestIdRef.current) return;

      if (finalQuery !== query) {
        setOptimizedQuery(finalQuery);
      }

      // Step 2: Search GitHub
      const data = await searchGitHub(finalQuery, filters);

      // If a new search started, abort
      if (currentId !== requestIdRef.current) return;

      setResults(data.items || []);
      setTotalCount(data.total_count || 0);

      if (data.items.length === 0) {
        setError("No results found. Try broader keywords.");
      }

    } catch (err: any) {
      if (currentId !== requestIdRef.current) return;
      setError(err.message || "Something went wrong.");
    } finally {
      if (currentId === requestIdRef.current) {
        setLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-x-hidden">

      {/* Background decoration */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-primary/5 blur-[120px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[30%] h-[30%] rounded-full bg-purple-600/5 blur-[100px]" />
      </div>

      {/* Main Content */}
      <div className="relative z-10 flex-1 flex flex-col">

        {/* Navigation / Header - visible when searching */}
        {isSearching && (
          <header className="sticky top-0 bg-background/80 backdrop-blur-md border-b border-border z-40 px-6 py-3 flex items-center justify-between animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex items-center gap-2 cursor-pointer" onClick={() => { setIsSearching(false); setQuery(''); setResults([]); }}>
              <Github className="text-white" />
              <span className="font-bold text-lg bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">GitScout</span>
            </div>

            <form onSubmit={handleSearch} className="flex-1 max-w-2xl mx-8 relative">
              <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-surface border border-border rounded-full py-2 pl-10 pr-4 text-sm text-white focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary transition-all"
              />
              <Search size={16} className="absolute left-3.5 top-2.5 text-slate-400" />
            </form>

            <button onClick={() => setFiltersOpen(!filtersOpen)} className={`p-2 rounded-lg transition-colors ${filtersOpen ? 'bg-primary/20 text-primary' : 'hover:bg-surface text-slate-400'}`}>
              <SlidersHorizontal size={20} />
            </button>
          </header>
        )}

        {/* Filter Bar (Expandable) */}
        {isSearching && filtersOpen && (
          <div className="bg-surface border-b border-border px-6 py-4 animate-in slide-in-from-top-2">
            <div className="max-w-7xl mx-auto flex flex-wrap gap-4 items-end">
              <div className="flex flex-col gap-1">
                <label className="text-[10px] uppercase font-bold text-secondary">Language</label>
                <select 
                  value={filters.language}
                  onChange={(e) => setFilters({...filters, language: e.target.value})}
                  className="bg-background border border-border rounded px-3 py-1.5 text-sm text-slate-200 min-w-[120px]"
                >
                  <option value="">Any</option>
                  <option value="javascript">JavaScript</option>
                  <option value="typescript">TypeScript</option>
                  <option value="python">Python</option>
                  <option value="rust">Rust</option>
                  <option value="go">Go</option>
                  <option value="java">Java</option>
                  <option value="cpp">C++</option>
                </select>
              </div>

              <div className="flex flex-col gap-1">
                <label className="text-[10px] uppercase font-bold text-secondary">Min Stars</label>
                <select 
                  value={filters.minStars}
                  onChange={(e) => setFilters({...filters, minStars: Number(e.target.value)})}
                  className="bg-background border border-border rounded px-3 py-1.5 text-sm text-slate-200"
                >
                  <option value="0">Any</option>
                  <option value="100">100+</option>
                  <option value="1000">1k+</option>
                  <option value="5000">5k+</option>
                  <option value="10000">10k+</option>
                </select>
              </div>

              <div className="flex flex-col gap-1">
                <label className="text-[10px] uppercase font-bold text-secondary">Sort By</label>
                <select 
                  value={filters.sort}
                  onChange={(e) => setFilters({...filters, sort: e.target.value as any})}
                  className="bg-background border border-border rounded px-3 py-1.5 text-sm text-slate-200"
                >
                  <option value="best-match">Relevance (Default)</option>
                  <option value="stars">Most Stars</option>
                  <option value="updated">Recently Updated</option>
                </select>
              </div>

              <button 
                onClick={() => handleSearch()}
                className="bg-primary hover:bg-blue-600 text-white px-4 py-1.5 rounded text-sm font-medium transition-colors ml-auto"
              >
                Apply Filters
              </button>
            </div>
          </div>
        )}

        {/* Center Search (Initial State) */}
        {!isSearching && (
          <div className="flex-1 flex flex-col items-center justify-center p-6 transition-all duration-500">
            <div className="mb-8 flex flex-col items-center animate-in fade-in zoom-in duration-700">
              <div className="bg-gradient-to-br from-blue-500/20 to-purple-600/20 p-4 rounded-3xl mb-4 border border-white/5">
                <Github size={64} className="text-white" />
              </div>
              <h1 className="text-5xl md:text-6xl font-black text-white tracking-tighter text-center">
                Git<span className="text-primary">Scout</span>
              </h1>
              <p className="text-slate-400 mt-4 text-lg text-center max-w-md">
                The AI-powered search engine for the GitHub universe. Finds what others miss.
              </p>
            </div>

            <form onSubmit={handleSearch} className="w-full max-w-2xl relative group">
              <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-purple-600 rounded-full blur opacity-25 group-hover:opacity-40 transition-opacity" />
              <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Describe what you want to build..."
                className="relative w-full bg-background border border-border rounded-full py-4 pl-14 pr-6 text-lg text-white placeholder:text-slate-500 shadow-2xl focus:outline-none focus:border-primary/50 transition-all"
                autoFocus
              />
              <Search size={24} className="absolute left-5 top-4 text-slate-400" />
              <button type="submit" className="absolute right-3 top-2.5 bg-surface hover:bg-slate-800 text-white p-2 rounded-full border border-border transition-colors">
                <ArrowRight size={20} />
              </button>
            </form>

            {/* Quick Chips */}
            <div className="mt-8 flex flex-wrap gap-2 justify-center opacity-0 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-200 fill-mode-forwards">
              {["Dashboard template", "Python web scraper", "React portfolio", "Machine learning model"].map((term) => (
                <button 
                  key={term}
                  onClick={() => { setQuery(term); handleSearch(); }}
                  className="px-4 py-1.5 rounded-full bg-surface border border-border text-sm text-slate-400 hover:text-white hover:border-primary/50 transition-all"
                >
                  {term}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Results Area */}
        {isSearching && (
          <main className="flex-1 max-w-7xl mx-auto w-full px-6 py-8">

            {/* AI Feedback */}
            {optimizedQuery && !loading && !error && (
              <div className="mb-6 flex items-center gap-2 text-sm text-slate-400 bg-surface/50 w-fit px-3 py-1.5 rounded-full border border-border animate-in fade-in">
                <Sparkles size={14} className="text-purple-400" />
                <span>Interpreted as: <span className="font-mono text-xs text-purple-300">{optimizedQuery}</span></span>
              </div>
            )}

            {/* Loading */}
            {loading && (
              <div className="flex flex-col items-center justify-center py-20">
                <Loader2 size={48} className="text-primary animate-spin mb-4" />
                <p className="text-slate-400 animate-pulse">Scouring the GitHub universe...</p>
              </div>
            )}

            {/* Error */}
            {error && (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                <div className="bg-red-500/10 p-4 rounded-full mb-4"><Search size={32} className="text-red-400" /></div>
                <h3 className="text-xl font-bold text-white mb-2">No results found</h3>
                <p className="text-slate-400 max-w-md">{error}</p>
              </div>
            )}

            {/* Grid */}
            {!loading && !error && results.length > 0 && (
              <>
                <p className="text-xs text-secondary mb-4 font-medium uppercase tracking-widest">{totalCount.toLocaleString()} Repositories Found</p>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
                  {results.map((repo) => (
                    <RepoCard 
                      key={repo.id} 
                      repo={repo} 
                      onChatContext={(r) => setActiveChatRepo(r)} 
                    />
                  ))}
                </div>
              </>
            )}
          </main>
        )}
      </div>

      <ChatAssistant 
        contextRepo={activeChatRepo} 
        onClearContext={() => setActiveChatRepo(null)} 
      />
    </div>
  );
};

export default App;

export interface GitHubRepo {
  id: number;
  node_id: string;
  name: string;
  full_name: string;
  private: boolean;
  owner: {
    login: string;
    avatar_url: string;
    html_url: string;
  };
  html_url: string;
  description: string | null;
  fork: boolean;
  created_at: string;
  updated_at: string;
  pushed_at: string;
  homepage: string | null;
  size: number;
  stargazers_count: number;
