import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, Minimize2, Trash2, Code2 } from 'lucide-react';
import { ChatMessage, GitHubRepo } from '../types';
import { sendChatMessage } from '../services/geminiService';

interface AIChatProps {
  isOpen: boolean;
  onClose: () => void;
  contextRepos: GitHubRepo[];
  onRemoveRepo: (repoId: number) => void;
}

const STORAGE_KEY = 'gitscout_chat_history';

const AIChat: React.FC<AIChatProps> = ({ isOpen, onClose, contextRepos, onRemoveRepo }) => {
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        return JSON.parse(saved);
      }
    } catch (e) {
      console.error("Failed to parse chat history", e);
    }
    return [{ id: 'init', role: 'model', content: 'Hi! I can help you understand repos, debug issues, or explain code. Select repositories to get specific help!', timestamp: Date.now() }];
  });

  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const prevContextRef = useRef<string>('');

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isOpen, isMinimized]);

  // Save messages to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  // Notify user when context changes
  useEffect(() => {
    if (contextRepos.length > 0) {
      const contextIds = contextRepos.map(r => r.id).sort().join(',');

      if (prevContextRef.current !== contextIds) {
        const names = contextRepos.map(r => r.name).join(', ');
        const contextMsg = `I see you're interested in: **${names}**. How can I help you compare or analyze these?`;

        setMessages(prev => {
           const lastMsg = prev[prev.length - 1];
           if (lastMsg?.content === contextMsg) return prev;
           return [...prev, { id: Date.now().toString(), role: 'model', content: contextMsg, timestamp: Date.now() }];
        });

        if (isMinimized) setIsMinimized(false);
        prevContextRef.current = contextIds;
      }
    }
  }, [contextRepos]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const history = messages.concat(userMsg).map(m => ({ role: m.role, content: m.content }));
      const context = contextRepos.map(r => `Repo: ${r.full_name}\nDesc: ${r.description}`).join('\n---\n');

      const response = await sendChatMessage(history, context);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: response, timestamp: Date.now() }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', content: "Sorry, I encountered an error.", timestamp: Date.now() }]);
    } finally {
      setLoading(false);
    }
  };

  const clearChat = () => {
    if (window.confirm("Are you sure you want to clear the chat history?")) {
      const initialMsg: ChatMessage = { id: Date.now().toString(), role: 'model', content: 'Chat history cleared. How can I help you?', timestamp: Date.now() };
      setMessages([initialMsg]);
      localStorage.setItem(STORAGE_KEY, JSON.stringify([initialMsg]));
    }
  };

  if (!isOpen) return null;

  if (isMinimized) {
    return (
      <button
        onClick={() => setIsMinimized(false)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full shadow-xl flex items-center justify-center text-white z-50 transition-all hover:scale-110"
      >
        <Bot size={28} />
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-[90vw] md:w-[400px] h-[600px] max-h-[80vh] bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl flex flex-col overflow-hidden z-50 animate-in slide-in-from-bottom-10 fade-in duration-300">
      {/* Header */}
      <div className="bg-slate-800 p-4 flex justify-between items-center border-b border-slate-700">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center">
            <Bot size={18} className="text-white" />
          </div>
          <div>
            <h3 className="font-bold text-slate-100">GitScout</h3>
            <p className="text-[10px] text-slate-400 flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
              Online
            </p>
          </div>
        </div>
        <div className="flex items-center gap-1 text-slate-400">
          <button 
            onClick={clearChat} 
            className="p-1.5 hover:bg-slate-700 rounded transition-colors hover:text-red-400"
            title="Clear Chat History"
          >
            <Trash2 size={16} />
          </button>
          <button onClick={() => setIsMinimized(true)} className="p-1.5 hover:bg-slate-700 rounded transition-colors">
            <Minimize2 size={16} />
          </button>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-700 rounded transition-colors hover:text-red-400">
            <X size={16} />
          </button>
        </div>
      </div>

      {/* Context Banner */}
      {contextRepos.length > 0 && (
        <div className="bg-slate-800/50 px-3 py-2 border-b border-slate-700 flex flex-col gap-1">
           <div className="flex items-center gap-2 text-xs text-blue-300 mb-1">
             <Code2 size={12} />
             <span className="font-semibold">Context ({contextRepos.length})</span>
           </div>
           <div className="flex flex-wrap gap-2 max-h-[80px] overflow-y-auto custom-scrollbar">
             {contextRepos.map(repo => (
               <div key={repo.id} className="flex items-center gap-1 bg-blue-900/40 border border-blue-500/30 text-blue-200 text-[10px] px-2 py-1 rounded-full">
                 <span className="truncate max-w-[150px]">{repo.name}</span>
                 <button 
                   onClick={() => onRemoveRepo(repo.id)}
                   className="hover:text-red-300 transition-colors"
                 >
                   <X size={10} />
                 </button>
               </div>
             ))}
           </div>
        </div>
      )}

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/95">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div 
              className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-br-none' 
                  : 'bg-slate-800 text-slate-200 rounded-bl-none border border-slate-700'
              }`}
            >
              <div className="whitespace-pre-wrap">{msg.content}</div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="bg-slate-800 rounded-2xl rounded-bl-none px-4 py-3 border border-slate-700 flex items-center gap-2">
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
              <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-slate-800 border-t border-slate-700">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={contextRepos.length > 0 ? "Ask about these repos..." : "Ask for debugging help..."}
            className="flex-1 bg-slate-900 border border-slate-600 text-slate-200 text-sm rounded-xl px-4 py-3 focus:outline-none focus:border-blue-500 transition-colors"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || loading}
            className="bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-xl disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default AIChat;

import { GitHubRepo, SearchFilters } from '../types';

const BASE_URL = "https://api.github.com/search/repositories";

export const searchGitHub = async (
  optimizedQuery: string, 
  filters: SearchFilters, 
  page: number = 1
): Promise<{ items: GitHubRepo[], total_count: number }> => {

  let q = optimizedQuery;

  // Append manual filters to the query string if not already present
  if (filters.language && !q.includes('language:')) {
    q += ` language:${filters.language}`;
  }
  if (filters.minStars > 0 && !q.includes('stars:')) {
    q += ` stars:>=${filters.minStars}`;
  }
  if (filters.owner && !q.includes('user:') && !q.includes('org:')) {
    q += ` user:${filters.owner}`;
  }

  const params = new URLSearchParams({
    q: q,
    per_page: "30", // High per_page to find "everything"
    page: page.toString()
  });

  if (filters.sort !== 'best-match') {
    params.append('sort', filters.sort);
    params.append('order', filters.order);
  }

  try {
    const res = await fetch(`${BASE_URL}?${params.toString()}`, {
      headers: {
        "Accept": "application/vnd.github.v3+json"
      }
    });

    if (!res.ok) {
      if (res.status === 403) throw new Error("GitHub API rate limit exceeded. Please wait a minute.");
      if (res.status === 422) throw new Error("Search query invalid or too long.");
      throw new Error(`GitHub Error: ${res.status}`);
    }

    const data = await res.json();
    return data;
  } catch (error) {
    console.error("GitHub API Error:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Search, Loader2, Sparkles, SlidersHorizontal, Github, ArrowRight } from 'lucide-react';
import { GitHubRepo, SearchFilters } from './types';
import { optimizeSearchQuery } from './services/geminiService';
import { searchGitHub } from './services/githubService';
import RepoCard from './components/RepoCard';
import ChatAssistant from './components/ChatAssistant';
import FilterBar from './components/FilterBar';

const App: React.FC = () => {
  // State
  const [query, setQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false); // UI state for search bar position
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<GitHubRepo[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [error, setError] = useState('');
  const [optimizedQuery, setOptimizedQuery] = useState('');
  const [filtersOpen, setFiltersOpen] = useState(false);
  const [activeChatRepo, setActiveChatRepo] = useState<GitHubRepo | null>(null);

  // Filters
  const [filters, setFilters] = useState<SearchFilters>({
    language: '',
    minStars: 0,
    sort: 'best-match',
    order: 'desc'
  });

  // Race Condition Handling
  const requestIdRef = useRef(0);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim()) return;

    setIsSearching(true);
    setLoading(true);
    setError('');
    setOptimizedQuery('');

    // Increment request ID
    const currentId = ++requestIdRef.current;

    try {
      // Step 1: Optimize Query with AI (The Google-like part)
      // We do this in parallel with a slight delay to the UI to show "Thinking..."
      let finalQuery = query;
      try {
        finalQuery = await optimizeSearchQuery(query);
      } catch (err) {
        console.warn("Optimization failed, using raw query");
      }

      // If a new search started, abort
      if (currentId !== requestIdRef.current) return;

      if (finalQuery !== query) {
        setOptimizedQuery(finalQuery);
      }

      // Step 2: Search GitHub
      const data = await searchGitHub(finalQuery, filters);

      // If a new search started, abort
      if (currentId !== requestIdRef.current) return;

      setResults(data.items || []);
      setTotalCount(data.total_count || 0);

      if (data.items.length === 0) {
        setError("No results found. Try broader keywords.");
      }

    } catch (err: any) {
      if (currentId !== requestIdRef.current) return;
      setError(err.message || "Something went wrong.");
    } finally {
      if (currentId === requestIdRef.current) {
        setLoading(false);
      }
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-x-hidden">

      {/* Background decoration */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-primary/5 blur-[120px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[30%] h-[30%] rounded-full bg-purple-600/5 blur-[100px]" />
      </div>

      {/* Main Content */}
      <div className="relative z-10 flex-1 flex flex-col">

        {/* Navigation / Header - visible when searching */}
        {isSearching && (
          <header className="sticky top-0 bg-background/80 backdrop-blur-md border-b border-border z-40 px-6 py-3 flex items-center justify-between animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex items-center gap-2 cursor-pointer" onClick={() => { setIsSearching(false); setQuery(''); setResults([]); }}>
              <Github className="text-white" />
              <span className="font-bold text-lg bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">GitScout</span>
            </div>

            <form onSubmit={handleSearch} className="flex-1 max-w-2xl mx-8 relative">
              <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-surface border border-border rounded-full py-2 pl-10 pr-4 text-sm text-white focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary transition-all"
              />
              <Search size={16} className="absolute left-3.5 top-2.5 text-slate-400" />
            </form>

            <button onClick={() => setFiltersOpen(!filtersOpen)} className={`p-2 rounded-lg transition-colors ${filtersOpen ? 'bg-primary/20 text-primary' : 'hover:bg-surface text-slate-400'}`}>
              <SlidersHorizontal size={20} />
            </button>
          </header>
        )}

        {/* Filter Bar (Expandable) */}
        {isSearching && filtersOpen && (
          <div className="bg-surface border-b border-border animate-in slide-in-from-top-2">
            <div className="max-w-7xl mx-auto">
               <FilterBar filters={filters} onChange={setFilters} />
               <div className="px-6 pb-4 flex justify-end">
                   <button 
                    onClick={() => handleSearch()}
                    className="bg-primary hover:bg-blue-600 text-white px-4 py-1.5 rounded text-sm font-medium transition-colors"
                  >
                    Apply Filters
                  </button>
               </div>
            </div>
          </div>
        )}

        {/* Center Search (Initial State) */}
        {!isSearching && (
          <div className="flex-1 flex flex-col items-center justify-center p-6 transition-all duration-500">
            <div className="mb-8 flex flex-col items-center animate-in fade-in zoom-in duration-700">
              <div className="bg-gradient-to-br from-blue-500/20 to-purple-600/20 p-4 rounded-3xl mb-4 border border-white/5">
                <Github size={64} className="text-white" />
              </div>
              <h1 className="text-5xl md:text-6xl font-black text-white tracking-tighter text-center">
                Git<span className="text-primary">Scout</span>
              </h1>
              <p className="text-slate-400 mt-4 text-lg text-center max-w-md">
                The AI-powered search engine for the GitHub universe. Finds what others miss.
              </p>
            </div>

            <form onSubmit={handleSearch} className="w-full max-w-2xl relative group">
              <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-purple-600 rounded-full blur opacity-25 group-hover:opacity-40 transition-opacity" />
              <input 
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Describe what you want to build..."
                className="relative w-full bg-background border border-border rounded-full py-4 pl-14 pr-6 text-lg text-white placeholder:text-slate-500 shadow-2xl focus:outline-none focus:border-primary/50 transition-all"
                autoFocus
              />
              <Search size={24} className="absolute left-5 top-4 text-slate-400" />
              <button type="submit" className="absolute right-3 top-2.5 bg-surface hover:bg-slate-800 text-white p-2 rounded-full border border-border transition-colors">
                <ArrowRight size={20} />
              </button>
            </form>

            {/* Quick Chips */}
            <div className="mt-8 flex flex-wrap gap-2 justify-center opacity-0 animate-in fade-in slide-in-from-bottom-4 duration-700 delay-200 fill-mode-forwards">
              {["Dashboard template", "Python web scraper", "React portfolio", "Machine learning model"].map((term) => (
                <button 
                  key={term}
                  onClick={() => { setQuery(term); handleSearch(); }}
                  className="px-4 py-1.5 rounded-full bg-surface border border-border text-sm text-slate-400 hover:text-white hover:border-primary/50 transition-all"
                >
                  {term}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Results Area */}
        {isSearching && (
          <main className="flex-1 max-w-7xl mx-auto w-full px-6 py-8">

            {/* AI Feedback */}
            {optimizedQuery && !loading && !error && (
              <div className="mb-6 flex items-center gap-2 text-sm text-slate-400 bg-surface/50 w-fit px-3 py-1.5 rounded-full border border-border animate-in fade-in">
                <Sparkles size={14} className="text-purple-400" />
                <span>Interpreted as: <span className="font-mono text-xs text-purple-300">{optimizedQuery}</span></span>
              </div>
            )}

            {/* Loading */}
            {loading && (
              <div className="flex flex-col items-center justify-center py-20">
                <Loader2 size={48} className="text-primary animate-spin mb-4" />
                <p className="text-slate-400 animate-pulse">Scouring the GitHub universe...</p>
              </div>
            )}

            {/* Error */}
            {error && (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                <div className="bg-red-500/10 p-4 rounded-full mb-4"><Search size={32} className="text-red-400" /></div>
                <h3 className="text-xl font-bold text-white mb-2">No results found</h3>
                <p className="text-slate-400 max-w-md">{error}</p>
              </div>
            )}

            {/* Grid */}
            {!loading && !error && results.length > 0 && (
              <>
                <p className="text-xs text-secondary mb-4 font-medium uppercase tracking-widest">{totalCount.toLocaleString()} Repositories Found</p>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-20">
                  {results.map((repo) => (
                    <RepoCard 
                      key={repo.id} 
                      repo={repo} 
                      onChatContext={(r) => setActiveChatRepo(r)} 
                    />
                  ))}
                </div>
              </>
            )}
          </main>
        )}
      </div>

      <ChatAssistant 
        contextRepo={activeChatRepo} 
        onClearContext={() => setActiveChatRepo(null)} 
      />
    </div>
  );
};

export default App;
